    library: str                        # 'sympy', 'numpy', etc.
    axiom_name: str                     # name in the LibraryTheory
    instantiation: Dict[str, OTerm] = field(default_factory=dict)
    statement: str = ''                 # the assertion being used
    version: str = ''                   # library version constraint

