# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_axioms._build_builtins_theory","kind":"function","src_hash":"899666ace9e93338","in":{"base":"Any"},"out":{"base":"LibraryTheory"},"spec":{"lhs":"_build_builtins_theory()","rhs":"theory for python builtins \u2014 sorted, len, range, etc","over":{"base":"Any"},"name":"_build_builtins_theory_correct"},"guarantee":"theory for python builtins \u2014 sorted, len, range, etc","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_axioms._build_builtins_theory_correct","statement":"Path(_build_builtins_theory(x), theory for python builtins \u2014 sorted, len, range, etc)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fd47bcdf0227b792"}
def _build_builtins_theory() -> LibraryTheory:
    """Theory for Python builtins — sorted, len, range, etc."""
    t = LibraryTheory("builtins")

    t.function("sorted",
        takes=[("iterable", "Iterable")],
        returns="list",
        ensures=[
            "result is a permutation of list(iterable)",
            "result is sorted in ascending order",
            "len(result) == len(list(iterable))",
        ],
        pure=True,
    )

    t.function("len",
        takes=[("obj", "Sized")],
        returns="int",
        ensures=["result >= 0"],
        pure=True,
    )

    t.function("range",
        takes=[("start", "int"), ("stop", "int"), ("step", "int")],
        returns="range",
        ensures=["len(result) == max(0, ceil((stop - start) / step))"],
        pure=True,
    )

    t.function("reversed",
        takes=[("seq", "Sequence")],
        returns="iterator",
        ensures=["list(result) == list(seq)[::-1]"],
        pure=True,
    )

    t.function("enumerate",
        takes=[("iterable", "Iterable"), ("start", "int")],
        returns="iterator",
        ensures=["result yields (start+i, x) for i, x in iteration"],
        pure=True,
    )

    t.function("zip",
        takes=[("*iterables", "Iterable")],
        returns="iterator",
        ensures=["len(list(result)) == min(len(it) for it in iterables)"],
        pure=True,
    )

    t.function("map",
        takes=[("func", "Callable"), ("iterable", "Iterable")],
        returns="iterator",
        ensures=["list(result) == [func(x) for x in iterable]"],
        pure=True,
    )

    t.function("filter",
        takes=[("func", "Callable"), ("iterable", "Iterable")],
        returns="iterator",
        ensures=["list(result) == [x for x in iterable if func(x)]"],
        pure=True,
    )

    # Equational axioms
    t.axiom("sorted_idempotent",
        statement="sorted(sorted(xs)) == sorted(xs)",
    )
    t.axiom("sorted_preserves_length",
        statement="len(sorted(xs)) == len(xs)",
    )
    t.axiom("len_nonneg",
        statement="len(xs) >= 0",
    )
    t.axiom("reversed_involution",
        statement="list(reversed(list(reversed(xs)))) == list(xs)",
    )
    t.axiom("map_compose",
        statement="list(map(f, map(g, xs))) == list(map(lambda x: f(g(x)), xs))",
    )
    t.axiom("filter_map_commute",
        statement="list(map(f, filter(p, xs))) == list(filter(p, map(f, xs)))",
        when=["p(x) == p(f(x)) for all x"],
    )

    return t


