# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_axioms._build_numpy_theory","kind":"function","src_hash":"c897fe2a5e052ef9","in":{"base":"Any"},"out":{"base":"LibraryTheory"},"spec":{"lhs":"_build_numpy_theory()","rhs":"theory for numpy \u2014 numerical computing","over":{"base":"Any"},"name":"_build_numpy_theory_correct"},"guarantee":"theory for numpy \u2014 numerical computing","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_axioms._build_numpy_theory_correct","statement":"Path(_build_numpy_theory(x), theory for numpy \u2014 numerical computing)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"27dd5381c8276e10"}
def _build_numpy_theory() -> LibraryTheory:
    """Theory for numpy — numerical computing."""
    t = LibraryTheory("numpy", version=">=1.20")

    t.function("dot",
        takes=[("a", "ndarray"), ("b", "ndarray")],
        returns="ndarray",
        requires=["a.shape[-1] == b.shape[0]"],
        ensures=[
            "result.shape == (*a.shape[:-1], *b.shape[1:])",
            "result is the matrix product of a and b",
        ],
        pure=True,
    )

    t.function("linalg.solve",
        takes=[("a", "ndarray"), ("b", "ndarray")],
        returns="ndarray",
        requires=["a is square", "a is non-singular"],
        ensures=["np.allclose(a @ result, b)"],
        raises=["LinAlgError"],
        pure=True,
    )

    t.function("linalg.inv",
        takes=[("a", "ndarray")],
        returns="ndarray",
        requires=["a is square", "a is non-singular"],
        ensures=["np.allclose(a @ result, np.eye(a.shape[0]))"],
        raises=["LinAlgError"],
        pure=True,
    )

    t.function("sort",
        takes=[("a", "ndarray")],
        returns="ndarray",
        ensures=[
            "result contains same elements as a",
            "result is sorted along last axis",
        ],
        pure=True,
    )

    t.function("zeros",
        takes=[("shape", "tuple[int, ...]")],
        returns="ndarray",
        ensures=["result.shape == shape", "all elements are 0.0"],
        pure=True,
    )

    t.function("ones",
        takes=[("shape", "tuple[int, ...]")],
        returns="ndarray",
        ensures=["result.shape == shape", "all elements are 1.0"],
        pure=True,
    )

    # Equational axioms
    t.axiom("dot_associative",
        statement="np.dot(np.dot(A, B), C) == np.dot(A, np.dot(B, C))",
        when=["shapes are compatible"],
    )
    t.axiom("dot_identity",
        statement="np.dot(A, np.eye(n)) == A",
        when=["A.shape[1] == n"],
    )
    t.axiom("inv_correct",
        statement="np.dot(A, np.linalg.inv(A)) == np.eye(n)",
        when=["A is n×n and non-singular"],
    )
    t.axiom("sort_idempotent",
        statement="np.sort(np.sort(a)) == np.sort(a)",
    )
    t.axiom("transpose_involution",
        statement="a.T.T == a",
    )

    return t


